def build_inverted_index(filename):
    inverted_index = {}

    with open(filename) as fin:
        for line in fin:
            for word in line.split():
                if word in inverted_index:
                    inverted_index[word].append(fin.tell())
                else:
                    inverted_index[word] = [fin.tell()]

    return inverted_index

